@@ -443,11 +443,22 @@ func (m *Manager) RemoveWithOptions(name string, force, nuclear bool) error {
 		if removeErr := os.RemoveAll(clonePath); removeErr != nil {
 			return fmt.Errorf("removing clone path: %w", removeErr)
